        static const unordered_map<string, string> lookup{{"0", "0"}, {"1", "1"},
                                                          {"6", "9"}, {"8", "8"}, 
                                                          {"9", "6"}};
        if (k == 0) {
            return {""};
        } else if (k == 1) {
            return {"0", "1", "8"};
